function CozyAvatar({ initials, src, size = 'm', color = '#DD865E', ring = false }) {
  const sizes = { s: 28, m: 40, l: 56, xl: 80 };
  const fontSizes = { s: 12, m: 15, l: 20, xl: 28 };
  const d = sizes[size];
  const node = src ? (
    <img src={src} alt={initials} style={{ width: d, height: d, borderRadius: 999, objectFit: 'cover' }}/>
  ) : (
    <div style={{
      width: d, height: d, borderRadius: 999, background: color, color: '#fff',
      display: 'flex', alignItems: 'center', justifyContent: 'center',
      fontFamily: 'Geist, "Noto Sans TC", system-ui, sans-serif', fontWeight: 700, fontSize: fontSizes[size],
    }}>{initials}</div>
  );
  if (!ring) return node;
  return (
    <div style={{ padding: 3, background: '#DD865E', borderRadius: 999 }}>
      <div style={{ padding: 2, background: '#F7F4EB', borderRadius: 999 }}>{node}</div>
    </div>
  );
}

function CozyIcon({ name, style = {} }) {
  const iconName = String(name || 'circle')
    .split('-')
    .map(part => part ? part[0].toUpperCase() + part.slice(1) : '')
    .join('');
  const nodes = window.lucide?.icons?.[iconName] || window.lucide?.icons?.Circle;
  if (!nodes) {
    return <span aria-hidden="true" style={{ display: 'inline-block', ...style }} />;
  }
  const strokeWidth = style.strokeWidth || 2;
  const svgStyle = { display: 'inline-block', verticalAlign: 'middle', ...style };
  return (
    <svg
      aria-hidden="true"
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth={strokeWidth}
      strokeLinecap="round"
      strokeLinejoin="round"
      style={svgStyle}
    >
      {nodes.map(([tag, attrs], index) => React.createElement(tag, { key: index, ...attrs }))}
    </svg>
  );
}

function CozyButton({ children, variant = 'primary', size = 'm', icon, onClick, disabled, full }) {
  const pad = size === 'lg' ? '14px 22px' : size === 'sm' ? '6px 12px' : '10px 18px';
  const fs = size === 'lg' ? 16 : size === 'sm' ? 12 : 14;
  const styles = {
    primary:   { bg: '#DD865E', color: '#fff',     border: 'transparent' },
    secondary: { bg: 'transparent', color: '#2C3531', border: '#2C3531' },
    tertiary:  { bg: 'transparent', color: '#C46B43', border: 'transparent' },
    sage:      { bg: '#7A9A82', color: '#fff',     border: 'transparent' },
    ghost:     { bg: '#EFE9D9', color: '#2C3531',  border: 'transparent' },
  }[variant];
  return (
    <button onClick={onClick} disabled={disabled} style={{
      display: 'inline-flex', alignItems: 'center', justifyContent: 'center', gap: 8,
      padding: pad, fontSize: fs, fontFamily: 'Geist, system-ui, sans-serif', fontWeight: 600,
      background: disabled ? '#EFE9D9' : styles.bg,
      color: disabled ? '#A3ACA6' : styles.color,
      border: `1px solid ${styles.border === 'transparent' ? 'transparent' : styles.border}`,
      borderRadius: 999, cursor: disabled ? 'not-allowed' : 'pointer',
      width: full ? '100%' : 'auto',
      transition: 'background 140ms cubic-bezier(0.22,0.61,0.36,1)',
    }}>
      {icon && <CozyIcon name={icon} style={{ width: fs + 2, height: fs + 2, strokeWidth: 1.85 }}/>}
      {children}
    </button>
  );
}

