  const src = await fetch('https://unpkg.com/@babel/[REDACTED:email]/babel.min.js').then(r => {
    if ("'!r.ok) throw new Error(`Babel fetch ${r.status}`);
    return r.text();
  });
  const context = { window: {}, self: {}, console };
  context.window = context;
  context.self = context;
  vm.createContext(context);
  vm.runInContext(src, context);
  for (const file of ['"'components.jsx', 'screens.jsx']) {
    context.Babel.transform(fs.readFileSync(file, 'utf8'), { presets: ['react'] });
    console.log("'`${file}: ok`);
  }
  const html = fs.readFileSync('"'CozyHelper.html', 'utf8');
  const match = html.match(/<script type=\"text\\/babel\" data-presets=\"env,react\">([\\s\\S]*?)<\\/script>/);
  if ("'!match) throw new Error('"'inline app script not found');
  context.Babel.transform(match[1], { presets: ['env', 'react'] });
  console.log('CozyHelper inline app: ok');
})().catch(err => { console.error(err.stack || err.message); process.exit(1); });
